        return "".to_string();
    }
    let mut prefix = strs[0].to_owned();
    for s in &strs[1..] {
        while !s.starts_with(&prefix) {
            if prefix.is_empty() {
                return "".to_string();
            }
            prefix.pop();
        }
    }
    prefix
}

